import Foundation

enum LocalWordList {
    static let words: Set<String> = {
        if let bundled = loadBundledWords() {
            return bundled
        }
        return fallbackWords()
    }()

    static func contains(_ word: String) -> Bool {
        words.contains(word.lowercased().trimmingCharacters(in: .whitespacesAndNewlines))
    }

    private static func loadBundledWords() -> Set<String>? {
        guard let url = Bundle.main.url(forResource: "scowl60_game_words", withExtension: "txt") else {
            return nil
        }
        guard let text = try? String(contentsOf: url, encoding: .utf8) else {
            return nil
        }

        let result = Set(
            text
                .split(whereSeparator: \.isNewline)
                .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() }
                .filter { !$0.isEmpty }
        )

        return result.isEmpty ? nil : result
    }

